# GCD (times sign of b if b is nonzero, times sign of a if b is zero)
def gcd(a,b):
 while b != 0:
     a,b = b, a % b
 return a

# Extended Greatest Common Divisor
def egcd(a, b):
 if (a == 0):
     return [b, 0, 1]
 else:
     g, y, x = egcd(b % a, a)
     return [g, x - (b // a) * y, y]

# Modular multiplicative inverse
def modInv(a, m):
 g, x, y = egcd(a, m)
